const item = $input.item.json;
return {
  email_msg_id: item.id,
  email_subject: item.subject,
  sender: item.from?.emailAddress?.address || null,
  received_at: item.receivedDateTime,
  action: 'skipped',
  error_msg: '非面試信件略過，略過',
};

const base = $('Code：萃取基本資訊').item.json;
let aiResult = {};
try {
  const raw = $input.item.json.content;
  const text = Array.isArray(raw) ? (raw[0]?.text || '') : (typeof raw === 'string' ? raw : '');
  const match = text.match(/\{[\s\S]*\}/);
  if (match) aiResult = JSON.parse(match[0]);
} catch(e) {}

// 修正後的安全防呆轉換
const ns = v => {
  if (v === null || v === undefined) return 'null';
  const str = String(v).trim();
  if (str === '' || str === 'null' || str === 'undefined') return 'null';
  return str;
};

const intent = aiResult.intent || 'recommend';
const candidateStatus = intent === 'cancel'
  ? 'withdrawn'
  : (['recommend', 'request_invite', 'other'].includes(intent) ? 'pending_review' : 'in_progress');
const interviewStatus = intent === 'cancel'
  ? 'cancelled'
  : (intent === 'update_time' ? 'rescheduled' : 'scheduled');

return {
  email_msg_id: base.email_msg_id,
  email_subject: base.email_subject,
  email_web_link: ns(base.email_web_link),
  sender: ns(base.sender),
  received_at: base.received_at,
  candidate_name: base.candidate_name || aiResult.candidate_name || '未知姓名',
  applied_position: ns(aiResult.applied_position) !== 'null' ? aiResult.applied_position : '未知職位',
  department: ns(aiResult.department) !== 'null' ? aiResult.department : '未分類',
  interview_date: ns(base.interview_date || aiResult.interview_date),
  interview_time: ns(base.interview_time || aiResult.interview_time),
  round: Number(aiResult.round) || 1,
  location: ns(aiResult.location),
  hr_owner: ns(aiResult.hr_owner),
  intent,
  status: candidateStatus,
  interview_status: interviewStatus,
};

const item = $input.item.json;
const subject = item.subject || '';
const rawBody = item.body?.content || item.bodyPreview || '';
const body = rawBody
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&#\d+;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const SKIP = new Set(['\u901a\u77e5','\u5b89\u6392','\u78ba\u8a8d','\u9762\u8a66','\u9080\u8acb','\u6642\u9593','\u5730\u9ede','\u66f4\u6539','\u66f4\u65b0','\u63a8\u85a6','\u53d6\u6d88','\u5c65\u6b77','\u56de\u8986']);
let candidateName = null;

const tailPatterns = [
  /?[^?]*?\s*[-???_~?:?]\s*([^\n]+?)\s*$/,
  /[-???_~?:?]\s*([^\n]+?)\s*$/,
  /?\s*([^\n]+?)\s*(?:\u5148\u751f|\u5973\u58eb|\u5c0f\u59d0)?\s*$/,
];

for (const pattern of tailPatterns) {
  const match = subject.match(pattern);
  if (!match || !match[1]) continue;
  const rawCandidate = match[1].trim().replace(/^(?:\u5148\u751f|\u5973\u58eb|\u5c0f\u59d0)\s*/, '');
  const compactCandidate = rawCandidate.replace(/\s+/g, '');
  if (!compactCandidate || compactCandidate.length > 30 || SKIP.has(compactCandidate)) continue;
  candidateName = compactCandidate;
  break;
}

let interviewDate = null;
const searchText = subject + ' ' + body.substring(0, 800);
const datePatterns = [
  { re: /(\d{4})?(\d{1,2})?(\d{1,2})?/, fn: m => `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}` },
  { re: /(\d{4})[\/\-.](\d{1,2})[\/\-.](\d{1,2})/, fn: m => `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}` },
  { re: /(\d{1,2})?(\d{1,2})?/, fn: m => `${new Date().getFullYear()}-${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}` },
];
for (const { re, fn } of datePatterns) {
  const m = searchText.match(re);
  if (m) { interviewDate = fn(m); break; }
}

let interviewTime = null;
const timeMatch = searchText.match(/(\d{1,2})[:?](\d{2})/);
if (timeMatch) {
  interviewTime = `${timeMatch[1].padStart(2,'0')}:${timeMatch[2]}`;
}

return {
  email_msg_id: item.id,
  email_subject: subject,
  email_web_link: item.webLink || null,
  sender: item.from?.emailAddress?.address || null,
  received_at: item.receivedDateTime,
  candidate_name: candidateName,
  interview_date: interviewDate,
  interview_time: interviewTime,
  body_text: body.substring(0, 2000),
};

const item = $input.item.json;

function splitCandidateNames(rawValue) {
  const value = String(rawValue || '').trim();
  if (!value || value === '\u672a\u77e5\u59d3\u540d') return [value || '\u672a\u77e5\u59d3\u540d'];

  const cleaned = value
    .replace(/[()??]/g, ' ')
    .replace(/(?:\u5148\u751f|\u5973\u58eb|\u5c0f\u59d0|\u540c\u5b78)/g, '')
    .replace(/\s+/g, '');

  const parts = cleaned
    .split(/[\/??,?;?]+/)
    .map(part => part.trim())
    .filter(Boolean);

  const names = (parts.length ? parts : [cleaned]).filter(name => name.length >= 2 && name.length <= 12);
  return [...new Set(names)];
}

const candidateNames = splitCandidateNames(item.candidate_name);
const originalEmailMsgId = String(item.email_msg_id || '');

return candidateNames.map((candidateName, index) => ({
  ...item,
  candidate_name: candidateName,
  original_email_msg_id: originalEmailMsgId,
  email_msg_id: candidateNames.length > 1 && originalEmailMsgId ? `${originalEmailMsgId}#${index + 1}` : originalEmailMsgId,
  multi_candidate_total: candidateNames.length,
  multi_candidate_index: index + 1,
  multi_candidate_names: candidateNames,
}));

