const item = $input.item.json;
const subject = item.subject || '';
const rawBody = item.body?.content || item.bodyPreview || '';
const body = rawBody
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&#\d+;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// 🌟 強化版：從主旨萃取候選人姓名
let candidateName = null;
const SKIP = new Set(['通知','安排','確認','面試','邀請','時間','地點','更改','更新','推薦','取消','履歷','回覆']);

// 涵蓋更多台灣職場常用的分隔符號與格式
const namePatterns = [
  /【[^】]*】\s*[-－—–_~～:：]\s*([a-zA-Z\u4e00-\u9fa5]{2,10})/, // 【職位】 - 姓名
  /[-－—–_~～]\s*([a-zA-Z\u4e00-\u9fa5]{2,10})\s*$/,          // - 姓名 (結尾)
  /】\s*([a-zA-Z\u4e00-\u9fa5]{2,10})\s*(?:先生|女士|小姐)/      // 】姓名先生
];

for (const p of namePatterns) {
  const m = subject.match(p);
  if (m && m[1]) {
    // 把抓到的字串去頭去尾空白
    const matchStr = m[1].trim(); 
    if (!SKIP.has(matchStr) && matchStr.length >= 2) {
      candidateName = matchStr;
      break;
    }
  }
}

// 如果正規表達式真的抓不到，做最後一道暴力防線：擷取主旨最後一個 "-" 後面的文字
if (!candidateName && subject.includes('-')) {
    const parts = subject.split(/[-－—–]/);
    const possibleName = parts[parts.length - 1].trim();
    if (possibleName.length >= 2 && possibleName.length <= 5 && !SKIP.has(possibleName)) {
        candidateName = possibleName;
    }
}

// 萃取日期（主旨 + body 前段）
let interviewDate = null;
const searchText = subject + ' ' + body.substring(0, 800);
const datePatterns = [
  { re: /(\d{4})年(\d{1,2})月(\d{1,2})日/, fn: m => `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}` },
  { re: /(\d{4})[\/\-.](\d{1,2})[\/\-.](\d{1,2})/, fn: m => `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}` },
  { re: /(\d{1,2})月(\d{1,2})日/, fn: m => `${new Date().getFullYear()}-${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}` },
];
for (const { re, fn } of datePatterns) {
  const m = searchText.match(re);
  if (m) { interviewDate = fn(m); break; }
}

// 萃取時間
let interviewTime = null;
const timeMatch = searchText.match(/(\d{1,2})[:：](\d{2})/);
if (timeMatch) {
  interviewTime = `${timeMatch[1].padStart(2,'0')}:${timeMatch[2]}`;
}

return {
  email_msg_id: item.id,
  email_subject: subject,
  email_web_link: item.webLink || null,
  sender: item.from?.emailAddress?.address || null,
  received_at: item.receivedDateTime,
  candidate_name: candidateName,
  interview_date: interviewDate,
  interview_time: interviewTime,
  body_text: body.substring(0, 2000),
};
